17	const maxHTTPErrorBody = 64 * 1024
18	
19	// httpError checks an HTTP response status and returns an error for non-2xx responses.
20	func httpError(res *http.Response) error {
21		if res.StatusCode >= http.StatusOK && res.StatusCode < http.StatusMultipleChoices {
22			return nil
23		}
24		var reason string
25		if res.Body != nil {
26			limited := io.LimitReader(res.Body, maxHTTPErrorBody+1)
27			data, err := io.ReadAll(limited)
28			if err == nil && len(data) > 0 {
29				if len(data) > maxHTTPErrorBody {
30					data = append(data[:maxHTTPErrorBody], []byte("...")...)
31				}
32				reason = string(data)
33			}
34		}
35		return fmt.Errorf("http %d: %s %s", res.StatusCode, res.Request.URL.Redacted(), reason)
36	}
