38	// StatsPhaseHeader is the HTTP header used to annotate requests with the
39	// current git-sync stats phase for round-trip tracking.
40	const StatsPhaseHeader = "X-Git-Sync-Stats-Phase"
41	
42	// AuthMethod authorizes outbound HTTP requests for a remote. It is satisfied
43	// by *transporthttp.BasicAuth and *transporthttp.TokenAuth, whose Authorizer
44	// methods replaced the AuthMethod interface that go-git removed in v6 alpha.2.
45	type AuthMethod interface {
46		Authorizer(req *http.Request) error
47	}
48	
49	// Conn represents a connection to a remote Git HTTP endpoint.
50	type Conn struct {
51		Label    string
52		Endpoint *url.URL
53		HTTP     *http.Client
54		Auth     AuthMethod
55	
56		// FollowInfoRefsRedirect, when true, rewrites Endpoint.Scheme and
57		// Endpoint.Host to the final URL returned by RequestInfoRefs after
58		// HTTP redirects. Subsequent PostRPC* calls then target the
59		// redirected host directly, matching vanilla git's smart-HTTP
60		// behaviour for discovery-aware servers that 307 /info/refs to a
61		// hosting replica. Endpoint.Path is never modified — it still
62		// contains the repo path. Off by default to preserve behaviour for
63		// callers that rely on Endpoint being stable.
64		FollowInfoRefsRedirect bool
65	}
66	
67	// NewConn creates a new connection to the given endpoint.
68	func NewConn(ep *url.URL, label string, auth AuthMethod, rt http.RoundTripper) *Conn {
69		httpClient := &http.Client{Transport: rt}
70		return NewConnWithHTTPClient(ep, label, auth, httpClient)
71	}
72	
73	// NewConnWithHTTPClient creates a new connection using the provided HTTP client.
74	// Passing nil falls back to a default client and is intended only for direct
75	// callers outside git-sync's normal instrumented session setup.
76	func NewConnWithHTTPClient(ep *url.URL, label string, auth AuthMethod, httpClient *http.Client) *Conn {
77		if httpClient == nil {
78			httpClient = &http.Client{Transport: http.DefaultTransport}
79		}
80		normalizeEndpointPath(ep)
81		return &Conn{
82			Label:    label,
83			Endpoint: ep,
84			HTTP:     httpClient,
85			Auth:     auth,
86		}
87	}
88	
89	func normalizeEndpointPath(ep *url.URL) {
90		if ep == nil {
91			return
92		}
93		ep.Path = strings.TrimRight(ep.Path, "/")
94		ep.RawPath = strings.TrimRight(ep.RawPath, "/")
95	}
96	
97	// NewHTTPTransport creates an http.Transport with optional TLS skip.
98	func NewHTTPTransport(skipTLS bool) http.RoundTripper {
99		if !skipTLS {
100			return http.DefaultTransport
101		}
102		if cloned, ok := http.DefaultTransport.(*http.Transport); ok {
103			tc := cloned.Clone()
104			if tc.TLSClientConfig == nil {
105				tc.TLSClientConfig = &tls.Config{MinVersion: tls.VersionTLS12}
106			}
107			tc.TLSClientConfig.InsecureSkipVerify = true
108			return tc
109		}
110		return http.DefaultTransport
111	}
112	
113	// RequestInfoRefs fetches /info/refs for the given service.
114	func RequestInfoRefs(ctx context.Context, conn *Conn, service string, gitProtocol string) ([]byte, error) {
115		reqURL := fmt.Sprintf("%s/info/refs?service=%s", conn.Endpoint.String(), service)
116		req, err := http.NewRequestWithContext(ctx, http.MethodGet, reqURL, nil)
117		if err != nil {
118			return nil, fmt.Errorf("create info-refs request: %w", err)
119		}
120		req.Header.Set("Accept", "*/*")
121		req.Header.Set("User-Agent", capability.DefaultAgent())
122		req.Header.Set(StatsPhaseHeader, service+" info-refs")
123		if gitProtocol != "" {
124			req.Header.Set("Git-Protocol", gitProtocol)
125		}
126		ApplyAuth(req, conn.Auth)
127	
128		res, err := conn.HTTP.Do(req)
129		if err != nil {
130			return nil, fmt.Errorf("request info-refs: %w", err)
131		}
132		defer res.Body.Close()
133		if err := httpError(res); err != nil {
134			return nil, err
135		}
136		wantContentType := fmt.Sprintf("application/x-%s-advertisement", service)
137		gotContentType := res.Header.Get("Content-Type")
138		gotMediaType := gotContentType
139		if gotContentType != "" {
140			if mediaType, _, err := mime.ParseMediaType(gotContentType); err == nil {
141				gotMediaType = mediaType
142			}
143		}
144		if gotMediaType != wantContentType {
145			return nil, fmt.Errorf("unexpected info/refs content-type %q, want %q", gotContentType, wantContentType)
146		}
147		if conn.FollowInfoRefsRedirect && res.Request != nil && res.Request.URL != nil {
148			final := res.Request.URL
149			if final.Host != conn.Endpoint.Host || final.Scheme != conn.Endpoint.Scheme {
150				conn.Endpoint.Scheme = final.Scheme
151				conn.Endpoint.Host = final.Host
152			}
153		}
154		// Bound the read to prevent unbounded memory allocation (issue #9).
155		const maxInfoRefsSize = 64 * 1024 * 1024 // 64 MiB
156		lr := io.LimitReader(res.Body, maxInfoRefsSize+1)
157		data, err := io.ReadAll(lr)
158		if err != nil {
159			return nil, fmt.Errorf("read info-refs response: %w", err)
160		}
161		if int64(len(data)) > maxInfoRefsSize {
162			return nil, fmt.Errorf("info/refs response exceeds %d byte limit", maxInfoRefsSize)
163		}
164		return data, nil
165	}
166	
167	// PostRPC sends a buffered POST to the given service and returns the full response body.
168	// Responses are bounded to prevent unbounded memory allocation (issue #9).
169	func PostRPC(ctx context.Context, conn *Conn, service string, body []byte, v2 bool, phase string) ([]byte, error) {
170		reader, err := PostRPCStream(ctx, conn, service, body, v2, phase)
171		if err != nil {
172			return nil, err
173		}
174		defer reader.Close()
175		const maxRPCResponse = 128 * 1024 * 1024 // 128 MiB
176		lr := io.LimitReader(reader, maxRPCResponse+1)
177		data, err := io.ReadAll(lr)
178		if err != nil {
179			return nil, fmt.Errorf("read RPC response: %w", err)
180		}
181		if int64(len(data)) > maxRPCResponse {
182			return nil, fmt.Errorf("RPC response for %s exceeds %d byte limit", service, maxRPCResponse)
183		}
184		return data, nil
185	}
186	
187	// PostRPCStream sends a POST to the given service and returns the response body
188	// as a streaming reader. Caller must close the returned ReadCloser.
189	func PostRPCStream(ctx context.Context, conn *Conn, service string, body []byte, v2 bool, phase string) (io.ReadCloser, error) {
190		return PostRPCStreamBody(ctx, conn, service, bytes.NewReader(body), v2, phase)
191	}
192	
193	// PostRPCStreamBody sends a POST to the given service using a streaming request body.
194	// Caller must close the returned ReadCloser.
195	func PostRPCStreamBody(ctx context.Context, conn *Conn, service string, body io.Reader, v2 bool, phase string) (io.ReadCloser, error) {
196		reqURL := fmt.Sprintf("%s/%s", conn.Endpoint.String(), service)
197		req, err := http.NewRequestWithContext(ctx, http.MethodPost, reqURL, body)
198		if err != nil {
199			return nil, fmt.Errorf("create RPC request: %w", err)
200		}
201		req.Header.Set("Content-Type", fmt.Sprintf("application/x-%s-request", service))
202		req.Header.Set("Accept", fmt.Sprintf("application/x-%s-result", service))
203		req.Header.Set("User-Agent", capability.DefaultAgent())
204		req.Header.Set(StatsPhaseHeader, phase)
205		if v2 {
206			req.Header.Set("Git-Protocol", "version=2")
207		}
208		ApplyAuth(req, conn.Auth)
209	
210		res, err := conn.HTTP.Do(req)
211		if err != nil {
212			return nil, fmt.Errorf("post RPC: %w", err)
213		}
214		if err := httpError(res); err != nil {
215			_ = res.Body.Close()
216			return nil, err
217		}
218		return res.Body, nil
219	}
220	
221	// ApplyAuth applies the given auth method to an HTTP request. Errors from
222	// the Authorizer (e.g. transient signing failures) are surfaced as request
223	// failures by leaving the Authorization header unset; the upstream server
224	// will reject with 401 and the caller logs the surrounding context.
225	func ApplyAuth(req *http.Request, auth AuthMethod) {
226		if auth == nil {
227			return
228		}
229		_ = auth.Authorizer(req) //nolint:errcheck // BasicAuth and TokenAuth never error; future authorizers should surface 401s instead
230	}
