450	type roundTripReader struct {
451		remaining int
452	}
453	
454	func (r *roundTripReader) Read(p []byte) (int, error) {
455		if r.remaining <= 0 {
456			return 0, io.EOF
457		}
458		n := len(p)
459		if n > r.remaining {
460			n = r.remaining
461		}
462		for i := range n {
463			p[i] = 'x'
464		}
465		r.remaining -= n
466		return n, nil
467	}
