410	func ObjectsToPush(store storer.EncodedObjectStorer, wants []plumbing.Hash, targetRefs map[plumbing.ReferenceName]plumbing.Hash) ([]plumbing.Hash, error) {
411		haveSet := make(map[plumbing.Hash]struct{})
412		for _, h := range targetRefs {
413			if !h.IsZero() {
414				haveSet[h] = struct{}{}
415			}
416		}
417	
418		filteredWants := make([]plumbing.Hash, 0, len(wants))
419		for _, h := range wants {
420			if _, ok := haveSet[h]; !ok {
421				filteredWants = append(filteredWants, h)
422			}
423		}
424		if len(filteredWants) == 0 {
425			return nil, nil
426		}
