	missing := plumbing.NewHash("cccccccccccccccccccccccccccccccccccccccc")
	_, err = ObjectsToPush(repo.Storer, []plumbing.Hash{missing}, nil)
	if err == nil {
		t.Fatal("expected error for missing want, got nil")
	}
	if !strings.Contains(err.Error(), "load want") {
		t.Errorf("expected error to mention 'load want', got: %v", err)
