// ObjectsToPush computes the set of objects that need to be sent to the target.
//
// Wants must be present in the store; this is verified up front so a missing
// want fails loudly rather than silently producing an empty pack. Transitive
// references encountered during the walk are allowed to be missing: a fetch
// with target refs as haves prunes the closure server-side, so any object
// reachable from a have is intentionally absent from the local store. Such
// objects are treated as implicitly have'd by the target and excluded from
// the push pack.
func ObjectsToPush(store storer.EncodedObjectStorer, wants []plumbing.Hash, targetRefs map[plumbing.ReferenceName]plumbing.Hash) ([]plumbing.Hash, error) {
	haveSet := make(map[plumbing.Hash]struct{})
	for _, h := range targetRefs {
		if !h.IsZero() {
			haveSet[h] = struct{}{}
		}
	}

	filteredWants := make([]plumbing.Hash, 0, len(wants))
	for _, h := range wants {
		if _, ok := haveSet[h]; !ok {
			filteredWants = append(filteredWants, h)
		}
	}
	if len(filteredWants) == 0 {
		return nil, nil
	}

	for _, h := range filteredWants {
		if _, err := store.EncodedObject(plumbing.AnyObject, h); err != nil {
			return nil, fmt.Errorf("load want %s: %w", h, err)
		}
	}

	seen := make(map[plumbing.Hash]bool, len(filteredWants)*4)
	objects := make([]plumbing.Hash, 0, len(filteredWants)*16)
	for _, h := range filteredWants {
		if err := collectObjects(store, h, haveSet, seen, &objects); err != nil {
			return nil, err
		}
	}
	return objects, nil
}

