// TestObjectsToPushMissingWant verifies a missing want still surfaces a
// loud error — we only tolerate missing transitive refs, not missing
// top-level wants.
func TestObjectsToPushMissingWant(t *testing.T) {
	repo, err := git.Init(memory.NewStorage(), nil)
	if err != nil {
		t.Fatalf("init repo: %v", err)
	}
	missing := plumbing.NewHash("cccccccccccccccccccccccccccccccccccccccc")
	_, err = ObjectsToPush(repo.Storer, []plumbing.Hash{missing}, nil)
	if err == nil {
		t.Fatal("expected error for missing want, got nil")
	}
	if !strings.Contains(err.Error(), "load want") {
		t.Errorf("expected error to mention 'load want', got: %v", err)
	}
}

