304	func openV2PackStream(body io.ReadCloser, verbose bool) (io.ReadCloser, error) {
305		reader := NewPacketReader(body)
306		for {
307			kind, payload, err := reader.ReadPacket()
308			if err != nil {
309				if errors.Is(err, io.EOF) {
310					return nil, io.ErrUnexpectedEOF
311				}
312				return nil, fmt.Errorf("decode protocol v2 fetch response: %w", err)
313			}
314			switch kind {
315			case PacketFlush:
316				return nil, io.ErrUnexpectedEOF
317			case PacketDelim, PacketResponseEnd:
318				continue
319			case PacketData:
320				line := string(payload)
321				if strings.HasPrefix(line, "ERR ") {
322					return nil, errors.New("remote: " + line[4:])
323				}
324				switch line {
325				case "packfile\n":
326					demux := sideband.NewDemuxer(sideband.Sideband64k, reader.BufReader())
327					demux.Progress = progressSink(verbose, "source: ")
328					return &wrappedRC{
329						Reader: demux,
330						Closer: body,
331					}, nil
332				case "acknowledgments\n":
333					if _, err := skipV2Acknowledgments(reader); err != nil {
334						return nil, err
335					}
336				case "shallow-info\n":
337					if err := SkipSection(reader); err != nil {
338						return nil, err
339					}
340				default:
341					return nil, fmt.Errorf("unexpected protocol v2 fetch section %q", strings.TrimSpace(line))
342				}
343			}
344		}
345	}
346	
347	func skipV2Acknowledgments(reader *PacketReader) (bool, error) {
348		ready := false
349		for {
350			kind, payload, err := reader.ReadPacket()
351			if err != nil {
352				return false, err
353			}
354			switch kind {
355			case PacketFlush:
356				if ready {
357					return false, errors.New("expected packfile to be sent after 'ready'")
358				}
359				return false, errors.New("protocol v2 fetch response ended without packfile after acknowledgments")
360			case PacketDelim:
361				if !ready {
362					return false, errors.New("unexpected delimiter in acknowledgments section without 'ready'")
363				}
364				return true, nil
365			case PacketData:
366				line := string(payload)
367				switch {
368				case line == "NAK\n", strings.HasPrefix(line, "ACK "):
369					continue
370				case line == "ready\n":
371					ready = true
372				default:
373					return false, fmt.Errorf("unexpected acknowledgment line %q", strings.TrimSpace(line))
374				}
375			case PacketResponseEnd:
376				return false, fmt.Errorf("unexpected packet type %v in acknowledgments section", kind)
377			default:
378				return false, fmt.Errorf("unexpected packet type %v in acknowledgments section", kind)
379			}
380		}
381	}
